INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('single','当代中国马克思主义、二十一世纪的马克思主义是指','["毛泽东思想", "邓小平理论", "科学发展观", "习近平新时代中国特色社会主义思想"]','习近平新时代中国特色社会主义思想','','导论'),
  ('single','习近平新时代中国特色社会思想的主要内容是','["“十个明确”、“十四个坚持” 和“十三个方面成就”", "“八个明确”和“十四个坚持”和“十三个方面成就”", "“五位一体”的总体布局", "“四个全面”的战略布局"]','“十个明确”、“十四个坚持” 和“十三个方面成就”','','导论'),
  ('single','二十大指出，习近平新时代中国特色社会思想的世界观和方法论是','["十一个必须坚持", "六个必须坚持", "五个必须坚持", "十个必须坚持"]','六个必须坚持','','导论'),
  ('single','习近平在庆祝中国共产党成立100周年大会上的讲话指出，要用马克思主义观察时代、把握时代、引领时代，要发展当代马克思主义必须坚持“两个结合”，这两个结合是指','["同中国具体实际相结合、同中华优秀传统文化相结合", "同中国生产力发展水平相结合、同儒家文化相结合", "同中国国情相结合、同中国传统文化相结合", "同中国改革开放实际相结合、同中国现代化建设实际相结合"]','同中国具体实际相结合、同中华优秀传统文化相结合','','导论'),
  ('single','习近平新时代中国特色社会思想形成的时间是','["十八大之后", "十九大之后", "二十大之后", "十九届六中全会之后"]','十八大之后','','导论'),
  ('single','中国特色社会主义的本质特征是','["解放生产力，发展生产力", "实现社会主义市场经济", "中国共产党的领导", "实现中华民族伟大复兴"]','中国共产党的领导','','导论'),
  ('single','中国特色社会主义制度的最大优势是','["实现社会主义公有制", "实现社会主义市场经济", "中国共产党的领导", "实现按劳分配"]','中国共产党的领导','','导论'),
  ('single','习近平新时代中国特色社会思想的根本价值立场是','["坚持人民至上", "坚持自信自立", "坚持守正创新", "坚持系统观念"]','坚持人民至上','','导论'),
  ('single','习近平新时代中国特色社会思想被写入党章是在','["十八大", "十九大", "十九届六中全会", "二十大"]','十九大','','导论'),
  ('multiple','习近平新时代中国特色社会思想回答了三大时代课题','["新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义", "建设什么样的社会主义现代化强国、怎样建设社会主义现代化强国", "建设什么样的长期执政的马克思主义政党、怎样建设长期执政的马克思主义政党", "什么是社会主义，怎样建设社会主义"]','新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义；建设什么样的社会主义现代化强国、怎样建设社会主义现代化强国；建设什么样的长期执政的马克思主义政党、怎样建设长期执政的马克思主义政党','','导论'),
  ('multiple','习近平新时代中国特色社会思想的科学体系包括','["六个必须坚持", "十个明确", "十三个方面成就", "十四个坚持"]','六个必须坚持；十个明确；十三个方面成就；十四个坚持','','导论'),
  ('multiple','习近平新时代中国特色社会思想是','["当代中国马克思主义、二十一世纪的马克思主义", "中华文化和中国精神的时代精华", "是马克思主义中国化时代化新的飞跃", "是“两个结合”的重大成果"]','当代中国马克思主义、二十一世纪的马克思主义；中华文化和中国精神的时代精华；是马克思主义中国化时代化新的飞跃；是“两个结合”的重大成果','','导论'),
  ('single','文化自信是实现中华民族伟大复兴的强大。','["思想武器", "精神力量", "精神动力", "动力源泉"]','精神力量','','第十章 建设社会主义文化强国'),
  ('single','坚持马克思主义在意识形态领域指导地位是坚持和加强党对宣传思想文化工作全面领导的。','["内在体现", "本质要求", "根本要求", "根本保障"]','本质要求','','第十章 建设社会主义文化强国'),
  ('single','坚持以为指导，是当代中国哲学社会科学区别于其他哲学社会科学的根本标志。','["马克思主义", "马克思主义理论", "马克思主义文化观", "社会主义"]','马克思主义','','第十章 建设社会主义文化强国'),
  ('single','是新闻舆论工作的根本原则。','["社会主义核心价值观", "社会主义道路", "党性原则", "社会主义制度"]','党性原则','','第十章 建设社会主义文化强国'),
  ('single','是一个民族赖以维系的精神纽带，是一个国家共同的思想道德基础。','["民族精神", "民族文化", "核心价值观", "核心价值观体系"]','核心价值观','','第十章 建设社会主义文化强国'),
  ('single','中国共产党人在中国特色社会主义新时代铸就的伟大精神，不包括。','["探月精神", "抗疫精神", "井冈山精神", "新时代北斗精神"]','井冈山精神','','第十章 建设社会主义文化强国'),
  ('single','社会主义核心价值观回答了我们要建设的国家 。','["富强民主文明和谐", "自由平等公正法治", "爱国敬业诚信友善", "富强美丽和平"]','（待AI复核）','','第十章 建设社会主义文化强国'),
  ('single','是新形势下做好新闻舆论工作的关键。','["管好用好互联网", "坚持正确的政治方向", "做大做强主流舆论阵地", "依法加强网络空间治理"]','管好用好互联网','','第十章 建设社会主义文化强国'),
  ('single','中华优秀传统文化是中华民族的。','["根和魂", "源头", "精华所在", "智慧结晶"]','根和魂','','第十章 建设社会主义文化强国'),
  ('single','推动社会文明程度的不断提高，是全面建设社会主义现代化国家的重要目标，也是建设的重大任务。','["中华文化", "中华文明", "社会主要核心价值观体系", "社会主义文化强国"]','社会主义文化强国','','第十章 建设社会主义文化强国'),
  ('single','实施是不断提高全体人民道德素质的灵魂工程。','["文化建设工程", "非物质文化遗产建设工程", "科教人才建设工程", "公民道德建设工程"]','公民道德建设工程','','第十章 建设社会主义文化强国'),
  ('single','中华文明的从根本上决定了中华民族必然走自己的路。','["连续性", "民族性", "独特性", "多样性"]','连续性','','第十章 建设社会主义文化强国'),
  ('single','中国共产党是中国先进文化的。','["引领者和践行者", "传承者和弘扬者", "引领者和弘扬者", "传承者和践行者"]','引领者和践行者','','第十章 建设社会主义文化强国'),
  ('single','保护好、传承好文化遗产，守护好中华文脉，要坚持把放在第一位。','["传承", "保护", "创造", "创新"]','保护','','第十章 建设社会主义文化强国'),
  ('single','讲好中国故事、传播好中国声音，根本在于','["以理服人", "以我为主", "传播理念", "以情动人"]','传播理念','','第十章 建设社会主义文化强国'),
  ('multiple','文化自信是的自信','["更基础", "更广泛", "更深厚", "更坚实"]','更基础；更广泛；更深厚','','第十章 建设社会主义文化强国'),
  ('multiple','互联网是意识形态斗争的','["主阵地", "主战场", "最前沿", "最远端"]','主阵地；主战场；最前沿','','第十章 建设社会主义文化强国'),
  ('multiple','坚持中国特色社会主义文化发展道路','["坚持举旗帜、聚民心、育新人、兴文化、展形象", "坚持“二为”方针“双百”方针", "激发全民族文化创新创造活力", "坚持“走出去”“引进来”"]','（待AI复核）','','第十章 建设社会主义文化强国'),
  ('multiple','下面是只有推动文化繁荣兴盛才能实现的目标','["充分发挥文化在价值塑造、共识凝聚方面的重要作用", "中华民族迎来实现伟大复兴的光明前景", "为全面推进中华民族伟大复习提供更为主动、更为强大的精神力量", "中华民族独立自强"]','充分发挥文化在价值塑造、共识凝聚方面的重要作用；为全面推进中华民族伟大复习提供更为主动、更为强大的精神力量','','第十章 建设社会主义文化强国'),
  ('multiple','关于革命文化、社会主义先进文化，下面说法错误的是','["它们以马克思主义为指导", "是坚定文化自信的深厚基础", "是中国共产党在伟大工程中孕育的", "与中华优秀传统文化一脉相承"]','是坚定文化自信的深厚基础；是中国共产党在伟大工程中孕育的','','第十章 建设社会主义文化强国'),
  ('multiple','全面建设社会主义现代化国家，我们应','["坚持中国特色社会主义文化道路", "建设社会主义文化强国", "发展社会主义文化", "激发全民族文化创新创造活力"]','坚持中国特色社会主义文化道路；建设社会主义文化强国；发展社会主义文化；激发全民族文化创新创造活力','','第十章 建设社会主义文化强国'),
  ('multiple','下面属于“兴文化”的是','["推动中华优秀传统文化创造性转化、创新性发展", "继承革命文化", "发展社会主义先进文化", "培养和践行社会主义核心价值观"]','推动中华优秀传统文化创造性转化、创新性发展；继承革命文化；发展社会主义先进文化','','第十章 建设社会主义文化强国'),
  ('multiple','新的时代条件下，党的新闻舆论工作的职责和使命是','["高举旗帜、引领导向，围绕中心、服务大局", "政府管理、企业履责，社会监督、网民自律", "团结人民、鼓舞士气，成风华人、凝心聚力", "澄清谬误、明辨是非，联结中外、沟通世界"]','高举旗帜、引领导向，围绕中心、服务大局；团结人民、鼓舞士气，成风华人、凝心聚力；澄清谬误、明辨是非，联结中外、沟通世界','','第十章 建设社会主义文化强国'),
  ('multiple','关于新时代新征程，坚持马克思主义在意识形态领域指导地位的根本制度，错误的说法是','["坚持走中国式现代化发展道路", "必须以经济建设为中心", "全面落实意识形态工作责任制", "坚持以立为本、立破并举，提高政治自觉"]','坚持走中国式现代化发展道路；必须以经济建设为中心','','第十章 建设社会主义文化强国'),
  ('multiple','新形势下，如何管好用好互联网','["推动互联网这个最大变化变成事业发展的最大增量", "坚持依法治网、依法办网、依法上网", "共建网上美好家园", "提高网络综合治理能力，推动形成良好网络生态"]','推动互联网这个最大变化变成事业发展的最大增量；坚持依法治网、依法办网、依法上网；共建网上美好家园；提高网络综合治理能力，推动形成良好网络生态','','第十章 建设社会主义文化强国'),
  ('judge','建设社会主义文化强国，只要继承了革命文化，发展了社会主义先进文化即可。','["正确", "错误"]','X','','第十章 建设社会主义文化强国'),
  ('judge','建设社会主义文化强国、推动社会主义文化繁荣兴盛，关键在于坚定中国特色社会主义文化自信。','["正确", "错误"]','正确','','第十章 建设社会主义文化强国'),
  ('judge','推动高质量发展，文化是重要支点。','["正确", "错误"]','正确','','第十章 建设社会主义文化强国'),
  ('judge','决定社会主义文化事业前途命运的关键，要传承中华文化。','["正确", "错误"]','X','','第十章 建设社会主义文化强国'),
  ('judge','意识形态关乎旗帜、关乎道路、关乎国家政治安全，决定文化前进方向和发展道路。','["正确", "错误"]','正确','','第十章 建设社会主义文化强国'),
  ('judge','社会主义核心价值观集中体现着全体人民共同的价值追求。','["正确", "错误"]','正确','','第十章 建设社会主义文化强国'),
  ('judge','中国社会主义文艺是社会主义时期的文艺，不能继承和发展中华优秀传统文艺。','["正确", "错误"]','X','','第十章 建设社会主义文化强国'),
  ('essay','如何铸就社会主义文化新辉煌？','[]','（简答题，请参照教材）','','第十章 建设社会主义文化强国'),
  ('essay','社会主义核心价值观如何引领文化建设？','[]','（简答题，请参照教材）','','第十章 建设社会主义文化强国'),
  ('single','是坚持立党为公、执政为民的本质要求。','["反腐败", "艰苦奋斗", "深化改革", "增进民生福祉"]','增进民生福祉','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','年是全面建成小康社会目标实现之年，是全面打赢脱贫攻坚战收官之年。','["2019", "2020", "2021", "2022"]','2020','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','面对突如其来的新冠肺炎疫情，我们坚持人民至上，坚持动态清零不动摇，开展抗击疫情人民战争、总体战、阻击战，最大限度保护了人民生命安全和身体健康，统筹疫情防控和经济社会发展取得重大积极成果。','["生命至上", "健康至上", "利益至上", "安全至上"]','生命至上','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','要统筹推进常态化疫情防控和经济社会发展，短期来看，是重点。','["全面建成小康社会", "稳需求，固经济", "扩大生产", "推动国际贸易发展"]','稳需求，固经济','','第十一章 以保障和改善民生为重点加强社会建设');
INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('single','全力推进就业扶贫，鼓励开发多种形式的扶贫专岗，动员更多贫困群众参与小型基础设施、农村人居环境整治等项目建设，以下不属于解决方式的是','["以工代贩", "以奖代补", "劳务雇佣", "劳务补助"]','劳务雇佣','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','“十四五”时期，实现基本全国统筹。','["养老保险", "医疗保险", "失业保险", "工伤保险"]','养老保险','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','抓民生也是抓发展。离开谈改善民生是无源之水、无本之木。','["经济发展", "政治文明", "文化繁荣", "社会和谐"]','经济发展','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','人民对美好生活的需要包括','[]','D','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','扎实推动共同富裕，不断增强人民群众','["获得感、满足感、安定感", "获得感、幸福感、安全感", "得到感、满足感、安全感", "得到感、幸福感、安定感"]','获得感、幸福感、安全感','','第十一章 以保障和改善民生为重点加强社会建设'),
  ('single','是解决民生问题的总钥匙。','["教育", "发展", "经济", "政治"]','发展','','第十一章 以保障和改善民生为重点加强社会建设'),
