  ('single','坚持中国特色国家安全道路，必须坚持总体国家安全观，以为宗旨。','["经济安全", "军事安全", "政治安全", "人民安全"]','人民安全','','第十三章 维护和塑造国家安全'),
  ('single','的核心是政权安全和制度安全，最根本的就是维护中国共产党的领导和执政地位、维护中国特色社会主义制度。','["经济安全", "军事安全", "政治安全", "人民安全"]','政治安全','','第十三章 维护和塑造国家安全'),
  ('single','与人民群众切身利益关系最密切，是人民群众安全感的晴雨表，是社会安定的风向标。','["经济安全", "军事安全", "政治安全", "社会安全"]','社会安全','','第十三章 维护和塑造国家安全'),
  ('single','是应对国家安全形势新变化新趋势的战略选择,是全面贯彻落实总体国家安全观的重大举措。','["统等稳定和发展", "构建新发展格局", "构建新安全格局", "建立强大的军队"]','构建新安全格局','','第十三章 维护和塑造国家安全'),
  ('single','维护政权安全,最主要是。','["建立强大的军队", "坚持和巩固马克思主义在意识形态领域的指导地位", "坚持和巩固党的领导和长期执政地位", "坚持和巩固人民民主专政"]','坚持和巩固党的领导和长期执政地位','','第十三章 维护和塑造国家安全'),
  ('multiple','以政治安全为根本，就是要坚持党的领导和中国特色社会主义制度不动摇，把放在首要位置，为国家安全提供根本政治保证。','["制度安全B.经济安全", "政权安全", "能源安全"]','制度安全B.经济安全；能源安全','','第十三章 维护和塑造国家安全'),
  ('multiple','总体国家安全观强调做好国家安全工作的系统思维和方法，应当统筹着力解决国家安全工作不平衡不充分的问题。','["统筹发展和安全", "统筹开放和安全", "统筹传统安全和非传统安全", "统筹自身安全和共同安全", "统筹维护国家安全和塑造国家安全"]','统筹发展和安全；统筹开放和安全；统筹传统安全和非传统安全；统筹自身安全和共同安全；统筹维护国家安全和塑造国家安全','','第十三章 维护和塑造国家安全'),
  ('multiple','建立健全防范风险机制，主要有','["风险研判机制", "决策风险评估机制", "风险防控协同机制", "风险防控责任机制"]','风险研判机制；决策风险评估机制；风险防控协同机制；风险防控责任机制','','第十三章 维护和塑造国家安全'),
  ('multiple','要坚持开放和安全的有机统筹，在保障安全中持续扩大开放，着力增强，创造有利于我国经济社会发展的安全环境，牢固树立开放型经济安全防线。','["经济发展能力", "自身竞争能力", "开放监管能力", "风险防控能力"]','自身竞争能力；开放监管能力；风险防控能力','','第十三章 维护和塑造国家安全'),
  ('multiple','推动创新发展、协调发展、绿色发展、开放发展、共享发展，前提都是','["国家安全", "经济飞跃", "文明发展", "社会稳定"]','国家安全；社会稳定','','第十三章 维护和塑造国家安全'),
  ('multiple','进入新时代,我国面临更为严峻复杂的国家安全形势,从外部环境来看,主要是。','["世界战略格局、全球治理体系、综合国力竞争进入深度变迁的历史进程", "气候变化、粮食安全、能源安全等全球性问题日趋尖锐复杂", "地区热点和局部冲突此起彼伏,国际局势变得更加复杂动荡", "和平与发展的时代主题面临严峻挑战"]','世界战略格局、全球治理体系、综合国力竞争进入深度变迁的历史进程；气候变化、粮食安全、能源安全等全球性问题日趋尖锐复杂；地区热点和局部冲突此起彼伏,国际局势变得更加复杂动荡；和平与发展的时代主题面临严峻挑战','','第十三章 维护和塑造国家安全'),
  ('multiple','总体国家安全观强调。','["做好国家安全工作的系统思维和方法,加强科学统筹", "维护国家安全要贯穿党和国家工作各方面全过程", "强调打总体战,形成汇聚党政军民学各战线各方面各层级的强大合力", "全社会全政府全体系全手段应对重大国家安全风险挑战"]','做好国家安全工作的系统思维和方法,加强科学统筹；维护国家安全要贯穿党和国家工作各方面全过程；强调打总体战,形成汇聚党政军民学各战线各方面各层级的强大合力；全社会全政府全体系全手段应对重大国家安全风险挑战','','第十三章 维护和塑造国家安全'),
  ('multiple','政治安全涉及国家的稳固,是一个国家最根本的需求。','["主权", "政权", "制度", "意识形态"]','主权；政权；制度；意识形态','','第十三章 维护和塑造国家安全'),
  ('judge','发展和安全是一体之两翼、驱动之双轮。发展是安全的基础和目的，安全是发展的条件和保障，发展和安全要同步推进。','["正确", "错误"]','正确','','第十三章 维护和塑造国家安全'),
  ('judge','政治安全是立国之基。','["正确", "错误"]','错误','','第十三章 维护和塑造国家安全'),
  ('judge','和平稳定的国际环境和国际秩序是国家安全的根本保障。','["正确", "错误"]','错误','','第十三章 维护和塑造国家安全'),
  ('judge','推动创新发展、协调发展、绿色发展、开放发展、共享发展，前提都是国家安全、社会稳定。','["正确", "错误"]','正确','','第十三章 维护和塑造国家安全'),
  ('judge','经过不懈努力，我国的国家主权、安全、发展利益得到全面维护，社会大局保持长期稳定。中国成为世界上最有安全感的国家。','["正确", "错误"]','错误','','第十三章 维护和塑造国家安全'),
  ('judge','没有网络安全就没有国家安全,就没有经济社会稳定运行,广大人民群众利益也难以得到保障。','["正确", "错误"]','正确','','第十三章 维护和塑造国家安全'),
  ('single','明确提出，党在新时代的强军目标是建设一支听党指挥、能打胜仗、作风优良的人民军队,把人民军队建设成为世界一流军队。','["2012年12月，中央军委扩大会议", "党的十九大", "2013年3月，十二届全国人大一次会议", "党的二十大"]','党的十九大','','第十四章 建设巩固国防和强大人民军队'),
  ('single','中国武装力量是指','["中国人民解放军的陆军、海军、空军、火箭军", "中国人民解放军和中国人民武装警察部队", "中国人民解放军、中国人民武装警察部队和民兵", "中国人民解放军和民兵"]','中国人民解放军、中国人民武装警察部队和民兵','','第十四章 建设巩固国防和强大人民军队'),
  ('single','关于党在新时代的强军目标，下列说法正确的是','["力争到本世纪中叶基本实现国防和军队现代化", "到2035年把人民军队全面建成世界一流军队", "确保到2020年全面实现机械化", "建设一支听党指挥、能打胜仗、作风优良的人民军队"]','建设一支听党指挥、能打胜仗、作风优良的人民军队','','第十四章 建设巩固国防和强大人民军队'),
  ('single','党对军队绝对领导是','["独立的领导", "直接的领导", "全面的领导", "独立的、直接的、全面的领导"]','独立的、直接的、全面的领导','','第十四章 建设巩固国防和强大人民军队'),
  ('single','党的十八大以来，以习近平同志为核心的党中央围绕新时代，深入进行理论探索和实践创造，形成习近平强军思想。','["坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义", "建设什么样的社会主义现代化强国、怎样建设社会主义现代化强国", "建设什么样的长期执政的马克思主义政党、怎样建设长期执政的马克思主义政党", "建设一支什么样的强大人民军队、怎样建设强大人民军队"]','建设一支什么样的强大人民军队、怎样建设强大人民军队','','第十四章 建设巩固国防和强大人民军队'),
  ('single','习近平强军思想明确是人民军队建军之本、强军之魂.','["政治工作", "党对人民军队的绝对领导", "练兵备战", "先进科技"]','党对人民军队的绝对领导','','第十四章 建设巩固国防和强大人民军队'),
  ('single','把作为唯一的根本的标准，是有效履行我军根本职能的内在要求，也是提高军队建设质量效益的客观需要。','["政治建军", "军事改革", "战斗力", "军事创新"]','战斗力','','第十四章 建设巩固国防和强大人民军队'),
  ('single','是民族复兴的根基，社会稳定是国家强盛的前提。','["经济发展", "国家安全", "文化教育", "依法治国"]','国家安全','','第十四章 建设巩固国防和强大人民军队'),
  ('single','在新时代的强军目标中，是核心。','["听党指挥", "能打胜仗", "作风优良", "全面建成世界一流军队"]','能打胜仗','','第十四章 建设巩固国防和强大人民军队'),
  ('single','90多年来，人民军队之所以能够始终保持强大的凝聚力向心力战斗力，经受住各种考验，不断从胜利走向胜利，最根本的就是靠。','["一不怕苦，二不怕死", "中国共产党的坚强领导", "改革开放的成功", "发展先进科学技术"]','中国共产党的坚强领导','','第十四章 建设巩固国防和强大人民军队'),
  ('single','是人民军队的鲜明特色和政治优势，也是人民军队战无不胜、攻无不克的重要保证。','["能打胜仗", "军民情谊", "听党指挥", "作风优良"]','作风优良','','第十四章 建设巩固国防和强大人民军队'),
  ('single','要充分发挥政治工作对强军兴军的生命线作用，培养有灵魂、、有血性、有品德的新时代革命军人。','["不怕苦", "有本事", "淡泊名利", "崇尚光荣"]','有本事','','第十四章 建设巩固国防和强大人民军队'),
  ('single','力争到二〇三五年国防和军队现代化，到本世纪中叶把人民军队世界一流军队。','["全面实现;基本建成", "全面实现;全面建成", "基本实现;基本建成", "基本实现;全面建成"]','基本实现;全面建成','','第十四章 建设巩固国防和强大人民军队');
INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('single','军队是要准备打仗的，一切工作都必须坚持标准，向能打仗、打胜仗聚焦。','["战斗力", "斗争力", "战争力", "硬实力"]','战斗力','','第十四章 建设巩固国防和强大人民军队'),
  ('single','是决定军队建设的政治方向','["军民融合是关键", "能打胜仗是核心", "听党指挥是灵魂", "作风优良是保证"]','听党指挥是灵魂','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','新的征程上，开创国防和军队现代化新局面，必须全面推进，加快把人民军队建设成为世界一流军队。','["政治建军B.改革强军C.科技强军D.人才强军E.依法治军"]','政治建军B.改革强军C.科技强军D.人才强军E.依法治军','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','新时代人民军队使命任务是。','["为巩固中国共产党领导和我国社会主义制度提供战略支撑", "为捍卫国家主权、统一和领土完整提供战略支撑", "为维护我国海外利益提供战略支撑D.为促进世界和平与发展提供战略支撑"]','为巩固中国共产党领导和我国社会主义制度提供战略支撑；为捍卫国家主权、统一和领土完整提供战略支撑；为维护我国海外利益提供战略支撑D.为促进世界和平与发展提供战略支撑','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','党在新时代强军目标的科学内涵是。','["听党指挥是灵魂，决定军队建设的政治方向", "能打胜仗是核心，反映军队的根本职能和军队建设的根本指向", "作风优良是保证，关系军队的性质、宗旨、本色", "体现了坚持党的建军原则、人民军队根本职能、特有政治优势的高度统一"]','听党指挥是灵魂，决定军队建设的政治方向；能打胜仗是核心，反映军队的根本职能和军队建设的根本指向；作风优良是保证，关系军队的性质、宗旨、本色；体现了坚持党的建军原则、人民军队根本职能、特有政治优势的高度统一','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','党在新时代的强军目标是建设一支的人民军队。','["听党指挥", "能打胜仗", "作风优良D.敢于创新"]','听党指挥；能打胜仗；作风优良D.敢于创新','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','到2035年，基本实现国防和军队现代化，这一步的关键是实现。','["军事理论现代化", "军队组织形态现代化", "军事人员现代化", "武器装备现代化"]','军事理论现代化；军队组织形态现代化；军事人员现代化；武器装备现代化','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','要着力培养新时代革命军人，锻造具有的过硬部队，确保我军永远立于不败之地。','["铁一般信仰", "铁一般信念", "铁一般纪律", "铁一般担当"]','铁一般信仰；铁一般信念；铁一般纪律；铁一般担当','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','深化国防和军队改革，要。','["按照军委管总、战区主战、军种主建的总原则改革领导指挥体制", "推进军队规模结构和力量编成改革，构建中国特色现代军事力量体系", "深化军队党的建设制度改革、创新军事力量运用政策制度", "重塑军事力量建设政策制度、改革军事管理政策制度", "建立健全中国特色社会主义军事政策制度体系"]','按照军委管总、战区主战、军种主建的总原则改革领导指挥体制；推进军队规模结构和力量编成改革，构建中国特色现代军事力量体系；深化军队党的建设制度改革、创新军事力量运用政策制度；重塑军事力量建设政策制度、改革军事管理政策制度；建立健全中国特色社会主义军事政策制度体系','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','提高军队战斗力，要。','["强化战斗队思想，立起练兵备战鲜明导向", "做到全部精力向打仗聚焦", "坚决破除“和平积弊”，把战斗力标准贯彻到全军各项建设中", "坚持用是否有利于提高战斗力来衡量和检验各项工作"]','强化战斗队思想，立起练兵备战鲜明导向；做到全部精力向打仗聚焦；坚决破除“和平积弊”，把战斗力标准贯彻到全军各项建设中；坚持用是否有利于提高战斗力来衡量和检验各项工作','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','公民在国防动员中应尽的责任和义务？','["依照法律服兵役", "履行国防勤务义务", "接受国防教育", "捐钱献物"]','依照法律服兵役；履行国防勤务义务；接受国防教育','','第十四章 建设巩固国防和强大人民军队'),
  ('multiple','军队党的作风建设主要任务之一是，严格落实中央八项规定精神、军委十项规定及其实施细则精神，持续整治。','["形式主义", "官僚主义", "享乐主义", "奢靡之风"]','形式主义；官僚主义；享乐主义；奢靡之风','','第十四章 建设巩固国防和强大人民军队'),
  ('judge','军政军民团结是实现富国和强军相统一的重要政治保障。要加强国防动员和后备力量建设，增强打赢未来战争的国防潜力。','["正确", "错误"]','错误','','第十四章 建设巩固国防和强大人民军队'),
  ('judge','关于实现党在新时代的强军目标是建设一支听党指挥、能打胜仗、作风优良的人民军队，把人民军队建设成为世界一流军队。','["正确", "错误"]','正确','','第十四章 建设巩固国防和强大人民军队'),
  ('judge','人民军队将在本世纪中叶基本实现国防和军队现代化。','["正确", "错误"]','错误','','第十四章 建设巩固国防和强大人民军队'),
  ('judge','深化国防和军队改革总体目标是，牢牢把握“军委管总、战区主战、军种主建”的原则。','["正确", "错误"]','正确','','第十四章 建设巩固国防和强大人民军队'),
  ('judge','改革是决定人民军队发展壮大、制胜未来的关键一招。','["正确", "错误"]','正确','','第十四章 建设巩固国防和强大人民军队'),
  ('single','“一国两制”伟大构想，最早是针对提出来的，这一构想获得了有关各方的一致认可，洗刷了民族百年耻辱，完成了实现祖国完全统一的重要一步。','["香港问题", "台湾问题", "澳门问题", "国家统一问题"]','台湾问题','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','我国是国家，中央对包括香港、澳门特别行政区在内的所有地方行政区域拥有全面管治权。','["单一制", "复合制", "邦联制", "联邦制"]','单一制','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','社会主义制度是中华人民共和国的根本制度，是中国特色社会主义最本质的特征，特别行政区所有居民应该自觉尊重和维护国家的根本制度。','["以人民为中心", "实现共同富裕", "发展民主政治", "中国共产党领导"]','中国共产党领导','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','依法治港治澳，是的应有之义，是全面准确贯彻“一国两制”方针的必由之路。','["爱国爱港爱澳B", "全面依法治国", "维护国家主权", "保证香港、澳门长治久安"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','2020年6月，十三届全国人大常委会第二十次会议通过,为香港特别行政区行政、立法和司法机关依法防范、制止和惩治危害国家安全的行为和活动提供了有力制度保障，筑牢了在香港特别行政区防控国家安全风险的制度屏障，成为维护香港稳定的“定海神针”。','["《香港特别行政区行政长官的产生办法》", "《中华人民共和国香港特别行政区基本法》", "《中华人民共和国香港特别行政区维护国家安全法》", "《在香港特别行政区实施的全国性法律》"]','《中华人民共和国香港特别行政区维护国家安全法》','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','是授权特别行政区高度自治的前提和基础，中央充分尊重和坚定维护香港、澳门特别行政区依法享有的高度自治权。','["全面管辖权", "地方事务管理权", "行政管辖权", "全面管治权"]','全面管治权','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','香港、澳门特别行政区政府大力加强对香港、澳门社会特别是青少年的宪法和基本法教育、、中国历史和中华文化教育，增强香港、澳门青少年的国家意识和爱国精神，努力使爱国爱港爱澳光荣传统薪火相传。','["国情教育", "“四史”教育", "爱国主义教育", "思想政治教育"]','国情教育','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','坚持以为核心的行政主导体制，支持行政长官和特别行政区政府依法施政、积极作为。','["行政长官", "特别行政区政府", "特别行政区司法制度", "特别行政区法律体系"]','行政长官','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','要进一步创新体制机制，发挥粤港澳综合优势，打造国际一流湾区和世界级城市群，使粤港澳大湾区成为的引领地。','["高质量发展", "中国式现代化", "转型升级", "实体经济"]','中国式现代化','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','香港、澳门多元文化共存，是中西文化交流的重要纽带。要保持香港、澳门国际性城市的特色，传播，宣介国家方针政策，讲好当代中国故事，发挥香港、澳门在促进东西方文化交流、文明互鉴、民心相通等方面的特殊作用。','["中国传统文化", "中国历史文化", "中华优秀文化", "中华传统文化"]','中华优秀文化','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','是两岸关系的政治基础。','["继续推进两岸“三通”", "促进两岸人文交流", "协商解决两岸同胞关心的问题", "一个中国原则"]','一个中国原则','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','一国两制就是在统一的国家之内，国家主体实行，个别地区依法实行资本主义制度。','["现代化", "军事工作", "社会主义制度", "资本主义制度"]','社会主义制度','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','坚持一个中国原则和,是推进祖国统一的政治基础。','["“九二共识”", "党中央对对台工作的集中统一领导", "在祖国大陆发展进步基础上解决台湾问题", "推动两岸关系和平发展、融合发展"]','“九二共识”','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','新时代党解决台湾问题的总体方略，科学回答了在民族复兴伟大进程中实现祖国完全统一的时代命题，标志着我们党的更加成熟。','["实现祖国统一理论", "对台大政方针", "国家统一理论", "台湾问题的总体方略"]','国家统一理论','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','取得的伟大成就，我国经济、科技国防实力的持续增强，包括台湾人民在内的全国各族人民万众一心、同仇敌忾，是我们解决台湾问题的最大底气。','["中国特色社会主义道路", "中国特色社会主义事业", "“五位一体”总体布局", "“四个全面”发展战略"]','中国特色社会主义事业','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','党的十八大以来，以习近平同志为核心的党中央从实现中华民族伟大复兴的全局高度，全面准确、坚定不移贯彻、、、高度自治的方针，推动香港进入由乱到治走向由治及兴的新阶段。','["“一国两制”", "促进两岸人文交流", "“港人治港”", "“澳人治澳”"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','“一国两制”伟大构想体现了中国共产党的政治智慧和开拓创新的勇气，体现了中华民族、、的精神特质和中国特色社会主义制度的先进性质。(ACD','["追求统一", "反对分裂", "爱好和平", "尊重差异"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','作为直辖于中央人民政府的香港、澳门特别行政区，享有高度自治权，包括、、和终审权。','["行政管理权", "立法权", "属地管辖权", "独立的司法权"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','“一国两制”作为党和国家的大政方针，必须通过具体的、、制度规则呈现出来、落到实处。','["制度体系", "制度安排", "制度规则", "制度建构"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','2022年7月，习近平在庆祝 香港回归祖国25周年大会暨香港特别行政区第六届政府就职典礼上的讲话中强调，中央全力支持香港抓住国家发展带来的历史机遇，主动对接、和高质量发展等国家战略；全力支持香港同世界各地展开更广泛、更紧密的交流合作。','["“十四五”规划", "粤港澳大湾区建设", "亚太经合组织", "“一带一路”"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','建立健全香港特别行政区维护国家安全的和。中央政府对香港特别行政区有关的国家安全事务负有根本责任，香港特别行政区负有维护国家安全的宪制责任。','["法律制度", "制度体系", "执行机制", "法律保障"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','要始终坚持,把特别行政区管治权牢牢掌握在爱国者手 中，这是事关国家主权、安全、发展利益，事关香港、澳门长期繁荣稳 定的根本原则，是保证香港、澳门长治久安的必然要求，任何时候都不 能动摇。','["“爱国者治港”", "港人治港", "“爱国者治澳”", "澳人治澳"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','香港是我国内地最大的、、。','["对外金融中心", "外资来源地", "对外投资最大目的地", "对外贸易最大转口地"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','两岸关系和平发展是、、的正确道路。','["维护两岸和平", "促进两岸共同发展", "造福两岸同胞", "实现中华民族伟大复兴"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('multiple','把握两岸关系和，推动两岸关系朝着正确方向发展，必须坚持一个中国原则和“九二共识”,坚决反对“台独”分裂行径，坚决反对外部势力干涉。','["主导权", "自主权", "决定权", "主动权"]','（待AI复核）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('judge','基本法是“一国两制”下特别行政区制度的本质属性和基本特征，特别行政区不存在一个脱离国家宪法的“宪制”和“法治”。','["正确", "错误"]','X','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('judge','中央有权对特别行政区高度自治权行使情况进行监督，有权依法对违反“一国两制”和基本法的行为予以纠正。','["正确", "错误"]','正确','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('judge','党的十九大以来，以习近平同志为核心的党中央把握历史大势和时代变化，丰富和发展国家统一理论和对台方针政策， 就对台工作提出一系列重要理念、重大政策主张。','["正确", "错误"]','X','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('judge','在中华民族的发展进程中，追求统一、反对分裂始终是全民族的主流价值观，这一价值观早已深深融入整个中华民族的精神血脉。','["正确", "错误"]','正确','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('judge','确保国家主权和领土完整是国家核心利益，是一条不可逾越的红线。','["正确", "错误"]','正确','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('essay','如何准确把握“一国”和“两制”的关系?','[]','（简答题，请参照教材）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('essay','为什么说祖国完全统一一定要实现，也一定能够实现?','[]','（简答题，请参照教材）','','第十五章 坚持"一国两制"和推进祖国完全统一'),
  ('single','，习近平在莫斯科国际关系学院发表题为《顺应时代前进潮流 促进世界和平发展》的演讲，指出这个世界越来越成为你中有我、我中有你的命运共同体，和平、发展、合作、共赢成为时代潮流。','["2012年11月", "2013年3月", "2014年5月", "2015年10月"]','2013年3月','','第十六章 中国特色大国外交和推动构建人类命运共同体');
INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('single','习近平是习近平新时代中国特色社会主义思想的重要组成部分，是马克思主义基本原理同中国特色大国外交实践相结合的重大理论成果，是以习近平同志为核心的党中央治国理政思想在外交领域的集中体现，是新时代我国对外工作的根本遵循和行动指南。','["外交理念", "外交理论", "外交思想", "关于外交的重要论述"]','外交思想','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','和发展中国家群体性崛起势不可当，将使全球发展的版图更加全面均衡，使世界和平的基础更为坚实稳固。','["欠发达国家", "新兴市场国家", "后发国家", "发达国家"]','新兴市场国家','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','作为国际社会积极、向上、建设性力量，应该坚定信念，直面风浪，以实际行动促进和平发展，维护公平正义，倡导民主自由，为处于动荡变革期的国际关系注入稳定性和正能量。','["上海合作组织", "亚太经合组织", "77国集团", "金砖国家"]','金砖国家','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','当前，世界百年变局和世纪疫情交织，单边主义、保护主义抬头，遭遇逆流。','["经济全球化", "世界多极化", "文化多样化", "社会信息化"]','经济全球化','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','当今世界面临的挑战需要各国携手应对和平赤字、发展赤字、安全赤字、，没有哪个国家能够独自应对人类面临的挑战，也没有哪个国家能够退回到自我封闭的孤岛。','["财政赤字", "民主赤字", "治理赤字", "管理赤字"]','治理赤字','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','习近平指出，站在新的历史起点上，联合国需要深入思考如何在21世纪更好回答世界和平与发展这一重大课题。当今世界，各国相互依存、休戚与共。我们要继承和弘扬联合国宪章的宗旨和原则，构建以合作共赢为核心的新型国际关系，打造。','["人类命运共同体", "世界共同体", "全球共同体", "政治共同体"]','人类命运共同体','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','构建人类命运共同体是为解决世界之问、人类之问、而提出的中国方案，需要国际社会从伙伴关系、安全格局、经济发展、文明交流、生态建设等方面作出努力。','["发展之问", "治理之问", "和平之问", "时代之问"]','时代之问','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','是习近平在博鳌亚洲论坛年会开幕式上郑重提出的。这一重大倡议明确回答了“世界需要什么样的安全理念、各国怎样实现共同安全”的时代课题，为应对国际安全挑战提供了中国方案。','["全球安全倡议", "全球发展倡议", "全球文明倡议", "全球数据安全倡议"]','全球安全倡议','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','截至2020年9月，中国军队先后参加项联合国维和行动，派出官兵近4万人次，有16名官兵献出宝贵生命。','["25", "20", "15", "10"]','25','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','是第一要务，适用于各国。要抓住新一轮科技革命和产业变革的历史性机遇，转变经济发展方式，坚持创新驱动，进一步发展社会生产力、释放社会创造力。','["改革", "发展", "开放", "变革"]','发展','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','要牢固树立尊重自然、顺应自然、保护自然的意识，解决好带来的矛盾，以人与自然和谐相处为目标，实现世界的可持续发展和人的全面发展。','["物质文明", "工业文明", "信息文明", "农业文明"]','工业文明','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','共建“一带一路”，秉持原则，坚持开放、绿色、廉洁理念，以高标准、可持续、惠民生为目标，全面推进政策沟通、设施联通、贸易畅通、资金融通、民心相通，努力建设和平之路、繁荣之路、开放之路、绿色之路、创新之路、文明之路。','["共商、共建、共享", "共建、共享、共治", "和平合作、开放包容", "互学互鉴、互利共赢"]','共商、共建、共享','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','推进改革和建设，是完善全球治理、增进世界各国民福祉的客观要求，也是构建人类命运共同体的内在要求。','["全球治理体系", "国际秩序", "国际政治秩序", "国际经济秩序"]','全球治理体系','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('single','中国坚持在基础上同各国发展友好合作，深化拓展平等、 开放、合作的全球伙伴关系。','["和平共处五项原则", "维护世界和平、促进共同发展", "独立自主", "加强和巩固同广大发展中国家的团结与合作"]','和平共处五项原则','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','中国走和平发展道路的自信和自觉','["来源于中华文明的深厚渊源", "来源于对实现中国发展目标条件的认知", "来源于对世界发展大势的把握", "来源于和平发展的大局"]','来源于中华文明的深厚渊源；来源于对实现中国发展目标条件的认知；来源于对世界发展大势的把握','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','中国在联合国、世界贸易组织、等多边机制中发挥越来越重要的作用，在国际舞台上发出更多中国声音、注入更多中国元素、提供更多中国方案。','["二十国集团", "金砖国家", "亚太经济合作组织", "上海合作组织"]','二十国集团；金砖国家；亚太经济合作组织；上海合作组织','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','走和平发展道路','["是我们党根据时代发展潮流和我国根本利益作出的战略抉择，是新时代中国外交的基本原则", "是对国际社会关注中国发展走向的回应，更是中国人民对实现自身发展目标的自信和自觉", "就要坚定奉行独立自主的和平外交政策", "既要通过维护世界和平发展自己，又要通过自身发展维护世界和平"]','是我们党根据时代发展潮流和我国根本利益作出的战略抉择，是新时代中国外交的基本原则；是对国际社会关注中国发展走向的回应，更是中国人民对实现自身发展目标的自信和自觉；就要坚定奉行独立自主的和平外交政策；既要通过维护世界和平发展自己，又要通过自身发展维护世界和平','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','构建人类命运共同体思想，是一个科学完整、内涵丰富、意义深远的思想体系，其核心内容除了建设持久和平的世界外，还包括建设','["普遍安全的世界", "共同繁荣的世界", "开放包容的世界", "清洁美丽的世界"]','普遍安全的世界；共同繁荣的世界；开放包容的世界；清洁美丽的世界','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','关于大国关系，以下说法正确的有','["促进大国协调和良性互动，推动构建和平共处、总体稳定、均衡发展的大国关系格局", "推进中俄新时代全面战略协作伙伴关系", "推动中美关系健康稳定发展", "打造中欧和平、增长、改革、文明四大伙伴关系"]','促进大国协调和良性互动，推动构建和平共处、总体稳定、均衡发展的大国关系格局；推进中俄新时代全面战略协作伙伴关系；推动中美关系健康稳定发展；打造中欧和平、增长、改革、文明四大伙伴关系','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','中国共产党愿在、互不干涉内部事务原则基础上加强同各国政党和政治组织交流合作，探索建立求同存异、相互尊重、互学互鉴的新型政党关系。','["独立自主", "自力更生", "完全平等", "互相尊重"]','独立自主；完全平等；互相尊重','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','金砖国家已成为国际事务中一支积极、稳定、建设性的重要力量。要同金砖国家深化战略伙伴关系，巩固“三轮驱动”合作架构。','["经贸财金", "政治安全", "文明交流", "人文交流"]','经贸财金；政治安全；人文交流','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('multiple','世界上没有绝对安全的世外桃源，一个国家的安全不能建立在别国的动荡之上，各方应该树立的安全观，统筹应对传统和非传统安全威胁，反对一切形式的恐怖主义。','["共同", "综合", "合作", "可持续"]','共同；综合；合作；可持续','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('judge','文明没有高下、优劣之分，没有特色、地域之别。','["正确", "错误"]','错误','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('judge','中国坚持走和平发展道路是思想自信和实践自觉的有机统一。','["正确", "错误"]','正确','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('judge','共建“一带一路”倡议不是推动构建人类命运共同体的实践平台。','["正确", "错误"]','错误','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('judge','中国始终把坚决维护国家主权、安全、发展利益作为外交工作的基本出发点和落脚点。','["正确", "错误"]','正确','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
  ('essay','如何理解人类命运共同体的内涵?','[]','（简答题，请参照教材）','','第十六章 中国特色大国外交和推动构建人类命运共同体'),
