  ('single','把人民对美好生活的向往作为奋斗目标，从根本上回答了的问题，是立党为公、执政为民的生动体现，是共产党人始终坚守的政治灵魂和精神支柱。','["“满足谁”", "“为了谁”", "“需要谁”", "“依靠谁”"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('single','面向未来，要战胜前进道路上的种种风险挑战，顺利实现二十大描绘的宏伟蓝图，必须紧紧依靠人民。正所谓“大鹏之动，非一羽之轻也；骐骥之速，非一足之力也”。中国要飞得高、跑得快，就得汇集和激发近14亿人民的磅礴力量。这是因为，人民群众是：','["第一生产力", "社会实践的主体", "社会存在和发展的基础", "事物发展的内在动力"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('single','让满意是我们党做好一切工作的价值取向和根本标准。','["领导", "群众", "世界", "企业家"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('single','是我们党的生命线和根本工作路线，使我们党永葆青春活力和战斗力的重要传家宝。','["群众路线", "干部路线", "文化路线", "经济路线"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('single','是中国特色社会主义的本质要求，是中国式现代化的重要特征。','["共同富裕", "人与自然和谐共生", "和平发展道路", "文化强国"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('single','中国共产党的宗旨是','["全心全意为人民服务", "全心全意为资本服务", "全心全意为领导服务", "全心全意为世界服务"]','（待AI复核）','','第四章 坚持以人民为中心');
INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('multiple','为什么说“人民是真正的英雄”？','["波澜壮阔的中华民族发展史是中国人民书写的", "博大精深的中华文明是中国人民创造的", "历久弥新的中华民族精神是中国人民培育的", "中华民族迎来了从站起来、富起来到强起来的伟大飞跃是中国人民奋斗出来的"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('multiple','中国共产党代表谁的利益，下列说法正确的是','["中国共产党是人民利益的忠实代表", "中国共产党从来不代表任何利益集团的利益", "中国共产党从来不代表任何权势团体的利益", "中国共产党从来不代表任何特权阶层的利益"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('multiple','以下关于共同富裕的理解，正确的是','["共同富裕是社会主义的本质要求，是中国式现代化的重要特征。", "共同富裕是全体人民共同富裕", "共同富裕只是人民群众物质生活富裕", "共同富裕不是整齐划一的平均主义"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('multiple','扎实推动共同富裕的基本原则指的是','[]','（待确认）','','第四章 坚持以人民为中心'),
  ('multiple','分配制度是促进共同富裕的基础性制度，坚持的制度体系。','["按劳分配为主体", "多种分配方式并存", "构建初次分配、再分配、第三次分配协调配套", "按劳动分配"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('judge','人民是历史的创造者，是决定党和国家前途命运的根本力量。','["正确", "错误"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('judge','组织路线始终是党的生命线和根本工作路线，是我们党永葆青春活力和战斗力的重要传家宝。','["正确", "错误"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('judge','中国共产党根基在人民、血脉在人民、力量在人民。人民是我们党的生命之根、执政之基、力量之源。','["正确", "错误"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('judge','“水能载舟、亦能覆舟”赢得人民信任、得到人民支持，党就能够克服任何困难。反之，我们将一事无成，甚至走向衰败。','["正确", "错误"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('judge','在中国共产党领导的社会主义中国，党性和人民性是一致的、统一的。','["正确", "错误"]','（待AI复核）','','第四章 坚持以人民为中心'),
  ('essay','为什么要坚持以人民为中心？','[]','（简答题，请参照教材）','','第四章 坚持以人民为中心'),
  ('essay','如何理解人民对美好生活的向往是党的奋斗目标？','[]','（简答题，请参照教材）','','第四章 坚持以人民为中心'),
  ('essay','为什么要坚持以人民为中心？','[]','（简答题，请参照教材）','','第四章 坚持以人民为中心'),
  ('essay','如何理解人民对美好生活的向往是党的奋斗目标？','[]','（简答题，请参照教材）','','第四章 坚持以人民为中心'),
  ('single','要破解发展中面临的难题，化解来自各方面的风险挑战，推动经济社会持续健康发展，必','[]','（待确认）','','第五章 全面深化改革开放'),
  ('single','40多年前开启的改革开放，是我们党的一次伟大觉醒，孕育了我们党从理论到实践的伟大创造。站在新的历史起点上，新时代中国共共产党人引领的全面深化改革，进一步将这场伟大觉醒引向更高境界。全面深化改革的出发点和落脚点是','["促进社会公平正义、增进人民福祉", "为人民谋幸福、为民族谋复兴", "实现国家富强、人民幸福", "解放和发展社会生产力、解放和增强社会活力"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','全面深化改革开放，不是某个领域某个方面的变革，而是涉及党和国家事业发展全局的体制机制变革。全面深化改革的重点是','["重要领域和关键环节改革", "经济体制改革", "制度建设", "统筹改革发展稳定"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','全面深化改革开放是一个复杂系统工程， 正确的方法对于改革顺利推进取得成功至关重要。富有中国特色、符合中国国情的改革方法是','["摸着石头过河", "正确处理改革发展稳定的关系", "加强顶层设计", "改革和法治同步推进"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','开放是国家繁荣发展的必由之路。着力发展开放型经济，要以','["“一带一路”建设为重点", "坚持走出去为重点", "坚持“引进来”和“走出去”并重为重点", "陆海内外联动、东西双向互济为重点"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','全面深化改革必须始终站稳人民立场，坚持的改革价值取向。','["以人民为中心", "社会主义本质要求", "党的性质宗旨", "社会主义发展"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','开放带来进步，封闭必然落后。我国发展要赢得优势、赢得主动、赢得未来，必须顺应经济全球化，依托我国超大规模市场优势，实行更加积极主动的开放战略，构建开放型经济体系，不断增强我国国际经济合作和竞争新优势。我国要构建的开放型经济体系的内容是','["“引进来”和“走出去”更好结合", "互利共赢、多元平衡、安全高效", "更大范围、更宽领域、更深层次", "以国内大循环为主体、国内国际双循环相互促进"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','中国特色社会主义制度及其执行能力的集中体现是','["人民当家作主制度体系", "党的领导制度体系", "国家治理体系和治理能力", "中国特色社会主义行政体制"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','全面深化改革开放是一个复杂系统工程， 正确的方法对于改革顺利推进取得成功至关重要。富有中国特色、符合中国国情的改革方法是','["摸着石头过河", "正确处理改革发展稳定的关系", "加强顶层设计", "改革和法治同步推进"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','在我国国家制度和国家治理体系的13个方面的显著优势中，排在第一位的是','["坚持全国一盘棋， 调动各方面积极性， 集中力量办大事的显著优势（    ）", "坚持人民当家作主，发展人民民主，密切联系群众，紧紧依靠人民推动国家发展的显著优势", "坚持以人民为中心的发展思想，不断保障和改善民生、增进人民福祉，走共同富裕道路的显著优势", "坚持党的集中统一领导、 确保国家始终沿着社会主义方向前进的显著优势"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','新冠疫情发生后，全国上下紧急行动，依托强大综合国力，开展全方位的人力组织战、物资保障战、科技突击战、资源运动战，全力支援湖北省和武汉市抗击疫情，在最短时间集中最大力量阻断疫情传播。一方有难，八方支援，体现了中国国家制度和国家治理体系的显著优势。这个显著优势是','["坚持人民当家作主", "坚持以人民为中心的发展思想", "坚持全国一盘棋", "坚持改革创新、与时俱进"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','中国连续4年修订外商投资准入负面清单，清单条目压缩幅度逾64.5%， 一批重大外资项目相继落地；外商投资法全面实施，清理与其不符的法规文件408部......近年来，我国不断优化营商环境，在世界银行《营商环境报告》中的排名从2018年的第78位跃升至2020年的第31位，连续2年跻身全球营商环境改善最快的前10个经济体之列。中国坚定不移支持建设开放型世界经济。开放型世界经济的首要之义是','["反对保护主义", "实现合作共赢", "反对单边主义", "倡导共商共建共享"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','改革发展稳定是我国社会主义现代化建设的三个重要支点。其中，发展是解决一切经济社会问题的关键。发展的根本目的是','["消除绝对贫困", "增进民生福祉", "跳出历史周期律", "促进社会稳定"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','党的十九届四中全会，对坚持和完善中国特色社会主义制度、推进国家治理体系和治理能力现代化作出总体璧画。以下表述不正确的是','["党成立100年时，在各方面制度更加成熟更加定型上取得明显成效", "2035年，各方面制度更加完善，基本实现国家治理体系和治理能力现代化", "新中国成立100年时全面实现国家治理体系和治理能力现代化，中国特色社会主义制度更加巩固、优越性充分展现", "本世纪中叶，全面建成符合社会主义现代化发展的国家治理体系"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('single','推进改革的目的是要不断推进我国社会主义制度，赋予社会主义新的生机活力。','["自我完善和发展", "现实性和实效性"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','1978 年，以党的十一届三中全会为标志，中国开启了改革开放历史征程。我们党作出实行改革开放的历史性决策，是基于','["对党和国家前途命运的深刻把握", "对社会主义革命和建设实践的深刻总结", "对时代潮流的深刻洞察", "对人民群众期盼和需要的深刻体悟"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','改革开放和社会主义现代化建设新时期，党面临的主要任务是','["继续探索中国建设社会主义的正确道路", "解放和发展社会生产力，使人民摆脱贫困、尽快富裕起来", "实现第一个百年奋斗目标，开启实现第二个百年奋斗目标新征程", "为实现中华民族伟大复兴提供充满新的活力的体制保证和快速发展的物质条件"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','1978年党的十一届三中全会开启了中国改革开放的历史征程。改革开放是','["党的一次伟大觉醒", "中国人民和中华民族发展史上一次伟大革命", "决定当代中国前途命运的关键一招", "实现中华民族伟大复兴的关键一步"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','党的十八大以来，以习近平同志为核心的党中央，从社会主义实践的历史经验和中国特色社会主义发展的现实需要出发，蹄疾步稳推进全面深化改革，拓展改革的广度和深度，全面深化改革的主体框架基本确立。以习近平同志为核心的党中央如此重视全面深化改革，是因为全面深化改革','["是具有新的历史特点的伟大斗斗争的重要方面", "是顺应当今世界发展大势的必然选择", "是破解发展中面临的难题，化解来自各方面的风险挑战，推动经济社会持续健康发展的要求", "关系党和人民事业前途命运，关系党的执政基础和执政地位"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','全面深化改革是“四个全面”战略布局中具有突破性和先导性的关键环节，是具有新的历史特点的伟大斗争的重要力面。全面深化改革要取得成功，必须','["坚持党对改革的集中统一领导", "坚持和完善中国特色社会主义制度", "坚持和完善国家治理体系", "坚持以人民为中心的改革价值取向"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','今日之中国，不仅是中国之中国，而且是世界之中国，开放的大门越开越大。中国开放的大门之所以越开越大，是因为','["开放带来进步，封闭必然落后", "开放是国家繁荣发展的必由之路", "对外开放是我国的基本国策", "开放也是改革，以开放促改革、促发展是我国现代化建设不断取得新成就的重要法宝"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','党的十八届三中全会通过了《中共中央关于全面深化改革若干重大问题的决定》，提出全面深化改革的总目标是完善和发展中国特色社会主义制度，推进国家治理体系和治理能力现代化。国家治理体系和国家治理能力的关系是','["国家治理体系和国家治理能力是等同的", "国家治理体系越完备国家治理能力就一定越强", "通过好的国家治理体系能够提高治理能力", "通过提高国家治理能力能够充分发挥国家治现体系的效能"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','改革开放是党和人民大踏步赶上时代的重要法宝，成为当代中国最鲜明的特色、当代中国共产党人最鲜明的品格。改革开放是','["我们党的一次伟大觉醒", "中国人民和中华民族发展史上一次伟大革命", "决定当代中国命运的关键一步", "决定实现“两个一百年”奋斗目标、实现中华民族伟大复兴的关键一招"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','新时代全面深化改革开放是一场深刻革命， 这是因为，全面深化改革开放是','["涉险滩、闯难关的变革", "一场思想理论的深刻变革、改革组织方式的深刻变革、国家制度和治理体系的深刻变革", "人民广泛参与的深刻变革", "在多年改革开放基础上的深化，是一场全面、 系统、整体的制度创新"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('multiple','全面深化改革开放改什么、怎么改，这是一个带有根本性的问题。习近平强调:“ 我们的改革开放是有方向、有立场、有原则的。”坚持全面深化改革开放的正确方向，必须','["坚持和改善党的全面领导", "坚持和完善中国特色社会主义制度", "坚持以人民为中心，促进社会公平正义、增进人民福祉", "有利于进一步解放思想、进一步解放和发展社会生产力、进一步解放和增强社会活力"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('judge','发展是解决一切经济社会问题的出发点和落脚点。','["正确", "错误"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('judge','全面深化改革的总目标是完善和发展中国特色社会主义制度，推进国家治理体系和治理能力现代化。','["正确", "错误"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('judge','党的十八届三中全会对全面深化改革进行了顶层设计、系统规划和总体部署，明确了全面深化改革总目标和主要任务。','["正确", "错误"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('judge','全面深化改革必须始终站稳人民立场，坚持以人民为中心的改革价值取向。','["正确", "错误"]','（待AI复核）','','第五章 全面深化改革开放'),
  ('judge','改革一定要按部就班，稳中求进。','["正确", "错误"]','（待AI复核）','','第五章 全面深化改革开放'),
