INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('essay','答：第一，改革开放永无止境是社会基本矛盾运动规律的深刻反映；','[]','（简答题，请参照教材）','','第五章 全面深化改革开放'),
  ('single','关于"新发展理念"，下列说法错误的是。','["共享发展注重的是解决发展内外联动问题", "开拓了中国特色社会主义政治经济学新境界", "回答了关于发展的目的、动力、方式、路径等一系列理论和实践问题", "绿色发展注重的是解决人与自然和谐共生问题"]','共享发展注重的是解决发展内外联动问题','','第六章 推动高质量发展'),
  ('single','经济发展是一个的过程，上升不是线性的，量积累到一定阶段，必须转向质的提升，我国经济发展也要遵循这一规律。','["螺旋式上升", "回旋式上升", "直线式上升", "波动式上升"]','螺旋式上升','','第六章 推动高质量发展'),
  ('single','推进宏观经济治理体系和治理能力现代化，要健全以财政政策和为主要手段的宏观经济治理体系。','["货币政策", "投资政策", "消费政策", "产业政策"]','货币政策','','第六章 推动高质量发展'),
  ('single','全面推进乡村振兴，要依托双层经营体制发展农业，以家庭经营为基础，坚持统分结合，积极培育新型农业经营主体，形成中国特色的农业规模经营。','["全方位", "均等", "统一", "适度"]','适度','','第六章 推动高质量发展'),
  ('single','协调发展，必须正确处理局部和全局、当前和长远、重点和非重点的关系，在发展中促进相对平衡，不断增强发展的。','["整体性", "可持续性", "系统性", "全局性"]','整体性','','第六章 推动高质量发展'),
  ('single','是国家经济现代化的重要标志。','["高质量城乡区域发展体系", "现代化市场体系", "现代化产业体系", "全面开放体系"]','现代化产业体系','','第六章 推动高质量发展'),
  ('single','建设统一开放、竞争有序、制度完备、治理完善的市场体系，是充分发挥我国超大规模市场优势的现实需要和必然选择。','["高效率", "高规格", "高质量", "高标准"]','高标准','','第六章 推动高质量发展'),
  ('single','是"十四五"乃至更长时期我国经济社会发展的主题，关系我国社会主义现代化建设全局。','["高质量发展", "脱贫攻坚", "结构性改革", "高速发展"]','高质量发展','','第六章 推动高质量发展'),
  ('single','新发展理念中，注重解决社会公平正义问题。','["共享", "创新", "协调", "开放"]','共享','','第六章 推动高质量发展'),
  ('single','构建高水平社会主义市场经济体制，关键是要处理好的关系。','["国家和企业", "政府和市场", "国家和市场", "政府和企业"]','政府和市场','','第六章 推动高质量发展'),
  ('multiple','新发展理念是指挥棒、红绿灯，是引领我国发展全局深刻变革的科学指引，必须完整、准确、全面地理解和把握。要从上把握新发展理念。','["问题导向", "忧患意识", "根本宗旨", "客观规律"]','问题导向；忧患意识；根本宗旨','','第六章 推动高质量发展'),
  ('multiple','着力推动实施扩大内需战略同深化供给侧结构性改革有机结合，要以满足国内需求为基本立足点，形成的更高水平的供需良性循环和动态平衡。','["需求创造供给", "供给创造需求", "需求牵引供给", "供给牵引需求"]','供给创造需求；需求牵引供给','','第六章 推动高质量发展'),
  ('multiple','进入新发展阶段，我国发展的国内外环境进一步发生深刻变化，面对新的，需要解决的矛盾和问题比以往更加错综复杂。','["战略机遇", "战略要求", "战略任务", "战略环境"]','战略机遇；战略要求；战略任务；战略环境','','第六章 推动高质量发展'),
  ('multiple','全面实施乡村振兴战略，要处理好的关系。','["长期目标和短期目标", "增强群众获得感和适应发展阶段", "顶层设计和基层探索", "充分发挥市场决定性作用和更好发挥政府作用"]','长期目标和短期目标；增强群众获得感和适应发展阶段；顶层设计和基层探索；充分发挥市场决定性作用和更好发挥政府作用','','第六章 推动高质量发展'),
