  ('single','党的十九届五中全会提出，坚持创新在我国现代化建设全局中的核心地位,把作为国家发展的战略支撑。','["科技自立自强", "人才引进", "共同富裕", "改革开放"]','科技自立自强','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','科技创新、是实现科技创新的两翼,要把科学普及放在与科技创新同等重要的位置。','["自主创新", "脱贫攻坚", "守正创新", "科学普及"]','科学普及','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','是科技创新的源头。我国面临的很多“卡脖子”技术问题，根子是基础理论研究跟不上。','["应用研究", "国家实验室", "经济特区", "基础研究"]','基础研究','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','是国之重器，对推动我国经济高质量发展、保障国家安全都具有十分重要的意义。','["科技创新", "新兴产业", "关键核心技术", "高新技术"]','关键核心技术','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','党的二十大报告指出，完善党中央对科技工作统一领导的体制，健全。','["文化体制", "经济体制", "科技体制", "新型举国体制"]','新型举国体制','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','是国家战略人才力量的源头活水。','["高层次人才", "尖子人才", "青年人才", "领军人才"]','青年人才','','第七章 社会主义现代化建设的教育科技人才战略');
INSERT INTO questions (type,title,options,answer,analysis,chapter) VALUES
  ('single','科教兴国是我国的。','["基本国策", "基本政策", "基本路线", "基本战略"]','基本国策','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','自力更生是中华民族自立于世界民族之林的奋斗基点,是我们攀登世界科技高峰的必由之路。','["自主创新", "科技创新", "调查研究", "信息技术"]','自主创新','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','习近平总书记在二十届中央政治局第五次集体学习时指出，要把作为建设教育强国的重要任务。','["提高科技水平", "增强驱动发展动力", "加强人才队伍建设", "服务高质量发展"]','服务高质量发展','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','如果把科技创新比作我国发展的新引擎，那么就是点燃这个新引擎必不可少的点火系。','["教育", "人才", "改革", "技术"]','改革','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('single','国家实验室、国家科研机构、高水平研究型大学、科技领军企业都是的重要组成部分。','["科技事业", "国家战略科技力量", "创新体系", "产业体系"]','国家战略科技力量','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','全面建设社会主义现代化国家,。','["教育是根本", "科技是关键", "人才是基础", "改革是保证"]','教育是根本；科技是关键；人才是基础','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','实施是增强综合国力、满足人民群众美好生活需要的必然要求，是建设教育强国、科技强国、人才强国的重大举措','["科教兴国战略", "人才强国战略", "创新驱动发展战略", "乡村振兴战略"]','科教兴国战略；人才强国战略；创新驱动发展战略','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','实施科教兴国战略，。','["是应对新时代环境变化的必然要求", "是建设创新型国家的必然要求", "是应对国际竞争的有力举措", "是决胜全面小康社会的重大部署"]','是应对新时代环境变化的必然要求；是建设创新型国家的必然要求；是应对国际竞争的有力举措','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','实施人才强国战略，，实施更加积极、更加开放、更加有效的人才政策。','["要坚持党管人才原则", "坚持尊重劳动、尊重知识、尊重人才、尊重创造", "完善人才战略布局", "深化人才发展体制机制改革"]','要坚持党管人才原则；坚持尊重劳动、尊重知识、尊重人才、尊重创造；完善人才战略布局；深化人才发展体制机制改革','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','实施创新驱动发展战略，，让创新成为全社会的共同行动。','["要坚持面向世界科技前沿、面向经济主战场", "要坚持面向国家重大需求、面向人民生命健康", "坚持科技创新，增强自主创新能力", "坚决打赢关键核心技术攻坚战"]','要坚持面向世界科技前沿、面向经济主战场；要坚持面向国家重大需求、面向人民生命健康；坚持科技创新，增强自主创新能力；坚决打赢关键核心技术攻坚战','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','教育优先发展，要做到，使我国教育越办越好。','["经济社会发展规划优先安排教育发展", "财政资金投入优先保障教育投入", "公共资源配置优先满足教育和人力资源开发需要", "推动健全优先发展教育事业的体制机制"]','经济社会发展规划优先安排教育发展；财政资金投入优先保障教育投入；公共资源配置优先满足教育和人力资源开发需要；推动健全优先发展教育事业的体制机制','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','必须坚持教育。','["为人民服务", "为中国共产党治国理政服务", "为巩固和发展中国特色社会主义制度服务", "为改革开放和社会主义现代化建设服务"]','为人民服务；为中国共产党治国理政服务；为巩固和发展中国特色社会主义制度服务；为改革开放和社会主义现代化建设服务','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','落实立德树人根本任务，必须着力解决好的问题，这是教育的根本问题，也是的核心课题。','["培养什么人", "怎样培养人", "为谁培养人", "建设教育强国"]','培养什么人；怎样培养人；为谁培养人；建设教育强国','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','我们培养的人，。','["要坚定共产主义远大理想和中国特色社会主义共同理想", "要有高尚的道德品质，厚植爱国主义情怀", "要养成刻苦学习的习惯", "要积极投身社会实践，增长经验和技能"]','要坚定共产主义远大理想和中国特色社会主义共同理想；要有高尚的道德品质，厚植爱国主义情怀；要养成刻苦学习的习惯；要积极投身社会实践，增长经验和技能','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('multiple','建设人才强国，必须。','["走好人才自主培养之路", "加快建设世界重要人才中心和创新高地", "坚持党对人才工作的全面领导", "深化人才发展体制机制改革"]','走好人才自主培养之路；加快建设世界重要人才中心和创新高地；坚持党对人才工作的全面领导；深化人才发展体制机制改革','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('judge','实现高水平科技自立自强是国家强盛和民族复兴的战略基石。','["正确", "错误"]','正确','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('judge','全面建成社会主义现代化强国关键看科技自立自强。','["正确", "错误"]','正确','','第七章 社会主义现代化建设的教育科技人才战略'),
  ('judge','科技创新是百年未有之大变局中的一个关键变量，世界主要国家纷纷把科技创新作为国际战略博弈的主要战场。','["正确", "错误"]','正确','','第七章 社会主义现代化建设的教育科技人才战略'),
